import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.Codec;

import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Encode user input to prevent XSS
        Codec codec = ESAPI.encoder();
        String encodedUserInput = codec.encodeForHTML(userInput);

        System.out.println("Hello, " + encodedUserInput + "!");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
